msg.payload = {
    phone_number: "0777123456",
    amount: 5.00,
    payment_method: "ecocash",
    payer_phone: "0777123456",
    qr_code: "BUS-TEST-" + Date.now()
};
msg.headers = {
    "Content-Type": "application/json"
};
return msg;

const response = msg.payload;

if (response.success && response.reference) {
