        actual: "PASSED ✓",
        details: response
    };
    node.status({fill:"green",shape:"dot",text:"PASSED"});
} else {
    msg.payload = {
        endpoint: "/api/trips/payment/initiate/",
        test: "Valid EcoCash Payment",
        expected: "Success with QR code",
        actual: "FAILED ✗",
        details: response
    };
    node.status({fill:"red",shape:"dot",text:"FAILED"});
}
return msg;

msg.payload = {
    phone_number: "invalid-phone",
    amount: 5.00,
    payment_method: "ecocash",
    payer_phone: "invalid-phone",
    qr_code: "BUS-INVALID-" + Date.now()
};
